import{_ as e,o,c as t,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"G09: 區域銷售分佈與地緣風險 - 企業風險評估專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/3189_景碩/20260423/G09_區域銷售分佈與地緣風險_企業風險評估專家.md","filePath":"審計報告庫/經營審計/3189_景碩/20260423/G09_區域銷售分佈與地緣風險_企業風險評估專家.md"}'),l={name:"審計報告庫/經營審計/3189_景碩/20260423/G09_區域銷售分佈與地緣風險_企業風險評估專家.md"};function i(_,a,n,d,c,h){return o(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="g09-區域銷售分佈與地緣風險-企業風險評估專家-審計報告" tabindex="-1">G09: 區域銷售分佈與地緣風險 - 企業風險評估專家 審計報告 <a class="header-anchor" href="#g09-區域銷售分佈與地緣風險-企業風險評估專家-審計報告" aria-label="Permalink to &quot;G09: 區域銷售分佈與地緣風險 - 企業風險評估專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>公司的區域銷售分佈與風險？地緣政治風險與匯率風險的影響有多大？客戶集中度是否構成營收結構風險？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>景碩為全球ABF載板第四大供應商（市佔率約12%），營收高度集中於AI/HPC晶片客戶（NVIDIA、AMD、Qualcomm、Broadcom、Google TPU），前五大客戶佔營收估&gt;70%，為極高集中度風險。區域面：95%+營收來自海外（以美國AI晶片設計公司為主），若美國對中國先進封裝技術進一步管制，景碩可能因封裝材料納入管制清單而間接受衝擊。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>B（持平）。客戶高度集中是載板產業結構性特徵（全球前三大載板廠集中度&gt;80%），短期無解。匯率風險：營收以美元報價&gt;85%，成本端原物料以日圓/美元混合計價，新台幣升值5%將侵蝕營業利益率約2-3%，2025年台幣升值壓力下匯兌損失風險上升。地緣風險評估為「中偏高」。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>客戶集中度分析</strong>：景碩主要客戶為AI晶片設計公司（NVIDIA Blackwell/Ultra GPU載板、AMD MI系列、Broadcom TPU ASIC、Google Axion），汽車晶片（Qualcomm Snapdragon Cockpit）約佔10-15%，網通/基地台晶片（Broadcom、Marvell）約10-15%。單一最大客戶NVIDIA估佔營收25-30%，一旦NVIDIA分散供應商將顯著衝擊營收。</p><p><strong>地緣政治風險</strong>：景碩工廠全在台灣。若台海局勢升溫，全球半導體供應鏈中斷的系統性風險不可忽視。此外，美國晶片法案禁止先進封裝技術流向中國，若ABF載板被擴大定義為「敏感技術」，景碩需減少對中國間接出貨（目前透過ASE/SMIC出貨估&lt;5%）。</p><p><strong>匯率壓力測試</strong>：新台幣每升值1%，營業利益影響約-2.5%。2025年台幣對美元升值約5-6%，對景碩獲利造成約15-18%的隱形侵蝕，此為無法對沖的結構性風險。景碩的避險工具僅有自然避險（部分原物料以美元採購）和遠期合約（約當20%曝險額度），避險覆蓋率偏低。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>景碩的營運模式本質上是「為美國AI晶片巨頭做載板加工」，議價權高度不對等。客戶集中度&gt;70%意味著任何一個主力客戶內部轉單（如NVIDIA分散部分訂單給Ibiden/欣興）都將立即反映在營收上。匯率風險屬被動承受型，公司無有效避險手段。</p><p>最值得警覺的地緣風險情境：中美科技戰升級至封裝材料禁運，ABF載板若被列入管制清單，景碩出貨將受雙向擠壓——美國客戶無法透過台灣載板商出貨給中國封測廠，中國客戶無法取得ABF載板供應，最終全球載板市場可能出現「雙軌制」供給分裂。</p><p>應對策略建議：景碩應分散客戶組合以降低單一客戶佔比（目標將NVIDIA佔比降至&lt;20%），同時加速建立非美元合約機制以降低匯率風險。長期策略上應評估在東南亞設立備援產線的可能性（目前無此計劃），以降低台海地緣政治風險集中的脆弱性。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>財報狗</code>: 景碩2025年營收地區別（客戶所在地，非出貨地）</li><li><code>經濟日報/中央社</code>: 法說會摘要（NVIDIA、AMD、Broadcom、Google TPU為主力客戶）</li><li><code>優分析UAnalyze</code>: 載板產業供應鏈報告（景碩全球市佔率12.4%）</li><li><code>yfinance</code>: 美元兌新台幣匯率波動（2025年台幣升值約5.6%）</li><li><code>IEK產業情報網</code>: ABF載板供需分析與中美管制風險評估</li></ul>',17)])])}const A=e(l,[["render",i]]);export{p as __pageData,A as default};
